script.text:

/* <flatten type="Javascript"> */
function load$Grid(g) {
  g.add_onResponseComplete(on$GridSalesInvoice$ResponseComplete);
  g.add_commandEvent(on$GridSalesInvoice$ExecuteCommand);
  g._$c0 = g._getColumnOrder('ma_sp');
  g._$c1 = g._getColumnOrder('ten_vt%l');
  g._$p = g._$n = '';
  g._$k = [];
}
function dispose$Grid(g) {
  g._$k = g._$p = g._$n = g._$c0 = g._$c1 = null
  try {g.remove_commandEvent(on$GridSalesInvoice$ExecuteCommand);} catch (ex) {}
  try {g.remove_onResponseComplete(on$GridSalesInvoice$ResponseComplete);} catch (ex) {}
}
function on$GridSalesInvoice$ExecuteCommand(sender, e) {
  var action = e.type.Action, g = sender;
  switch (action) {
    case 'ImportData':
      show$Form(g, 'BMTranImport');
      break;
    case 'Download':
      request$Download(g, action);
      break;
    case 'GetBOMView':
      if (g._activeRow == -1) return;
      g._$p = g._getItemValue(g._activeRow, g._$c0);
      g._$n = g._getItemValue(g._activeRow, g._$c1);
      g.request(g, 'GetBOMView', 'GetBOMView', [['code', 'String', g._$p]]);
      break;
    default:
      break;
  }
}
function on$GridSalesInvoice$ResponseComplete(sender, e) {
  var g = e.object, context = e.type.Context, result = e.type.Result, o = e.type.Object, msg;
  switch (context) {
    case 'Download':
      g._key = result[0].Value;
      break;
    case 'GetBOMView':
      if (result[0].Value == 0) {
        msg = ((g._language == 'v') ? 'Sản phẩm <span class="Highlight">%s</span> khai báo không đúng.' : 'Product <span class="Highlight">%s</span> is invalid.');
        $message.show(msg.replace("%s", g._$p));
        if (g._$k != null) g._$k = [];
        break;
      } else {
        g._$k = result;
        if (g._$k.length <= 0) break;
        g.showForm('BMTranView');
      }
      break;
    default:
      break;
  }
}
function show$Form(g, c) {
  (g._authorize == 1) && (!g._denyNew) ? g.showForm(c) : $message.show(g._denyMessage ? g._denyMessage : $df.getResources(g._language, "Message.NotAccess"));
}
/* </flatten> */

      &DowloadScript;

